public class Practice {
  public static void main(String[] args) {
    int[] nums = {10, 20, 5, 7};
    int sum = 0;
    for (int i = 0; i < nums.length - 1; i++) {
      sum += nums[i];
    }
    System.out.println(sum);
  }
}
